def test_encounter_state_transition_planned_to_finished_audit_captured(clinician_auth_token, existing_patient_id, api_base_url):
    create_payload = {
        "resourceType": "Encounter",
        "status": "planned",
        "subject": {"reference": f"Patient/{existing_patient_id}"},
        "period": {"start": "2024-07-01T07:00:00Z"}
    }
    create_resp = <api_post>(f"{api_base_url}/Encounter", json=create_payload, token=clinician_auth_token)
    assert create_resp.status_code == 201
    enc_id = create_resp.json()["id"]

    update_payload = {
        "resourceType": "Encounter",
        "id": enc_id,
        "status": "finished",
        "subject": {"reference": f"Patient/{existing_patient_id}"},
        "period": {"start": "2024-07-01T07:00:00Z", "end": "2024-07-01T08:00:00Z"}
    }
    update_resp = <api_put>(f"{api_base_url}/Encounter/{enc_id}", json=update_payload, token=clinician_auth_token)
    assert update_resp.status_code == 200
    assert update_resp.json()["status"] == "finished"

    audit_resp = <api_get>(
        f"{api_base_url}/AuditEvent",
        params={"entity": f"Encounter/{enc_id}"},
        token=clinician_auth_token
    )
    entries = audit_resp.json().get("entry", [])
    audit_actions = {e["resource"]["action"] for e in entries}
    assert "C" in audit_actions
    assert "U" in audit_actions

    <cleanup_resource>(f"{api_base_url}/Encounter/{enc_id}", token=clinician_auth_token)
